/* html2canvas - Screenshot & Canvas Rendering */
/* Uses CDN with proper promise-based loading */

if (!window.html2canvasPromise) {
  window.html2canvasPromise = new Promise((resolve, reject) => {
    if (window.html2canvas && typeof window.html2canvas === 'function') {
      console.log('[html2canvas] Already loaded');
      resolve(window.html2canvas);
      return;
    }

    console.log('[html2canvas] Loading from CDN...');
    var script = document.createElement('script');
    script.src = 'https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js';
    script.async = true;
    
    var timeout = setTimeout(() => {
      reject(new Error('html2canvas CDN load timeout'));
    }, 10000);
    
    script.onload = function() {
      clearTimeout(timeout);
      if (window.html2canvas && typeof window.html2canvas === 'function') {
        console.log('[html2canvas] Successfully loaded from CDN');
        resolve(window.html2canvas);
      } else {
        reject(new Error('html2canvas loaded but not available'));
      }
    };
    
    script.onerror = function() {
      clearTimeout(timeout);
      console.error('[html2canvas] CDN load failed');
      window.html2canvas = function() { return Promise.reject(new Error('html2canvas not available')); };
      reject(new Error('html2canvas CDN failed'));
    };
    
    document.head.appendChild(script);
  });
}
